import{_ as o,c,o as d,ae as t}from"./chunks/framework.z0sZ1NT9.js";const l="/blog/assets/react-core.BzQQ1b2U.png",h=JSON.parse('{"title":"react原理","description":"","frontmatter":{},"headers":[],"relativePath":"articles/frontend/react原理.md","filePath":"articles/frontend/react原理.md"}'),r={name:"articles/frontend/react原理.md"};function i(a,e,n,s,u,f){return d(),c("div",null,e[0]||(e[0]=[t('<h1 id="react原理" tabindex="-1">react原理 <a class="header-anchor" href="#react原理" aria-label="Permalink to &quot;react原理&quot;">​</a></h1><p>本文档介绍 React 的原理（待完善）。</p><h2 id="核心包关系图分析" tabindex="-1">核心包关系图分析 <a class="header-anchor" href="#核心包关系图分析" aria-label="Permalink to &quot;核心包关系图分析&quot;">​</a></h2><p><img src="'+l+'" alt="核心包关系图"></p><p>下面为基于文档中 <code>react-core.png</code> 的详尽说明，按职责分层并补充示例调用序列，便于把抽象流程对应到源码实现。</p><p>一、总体分工（一句话概括）</p><ul><li><code>react-reconciler</code>：负责构建/调和 Fiber 树（计算差异、收集副作用）。</li><li><code>scheduler</code>：负责按优先级/时间切片调度调和工作，决定何时运行 reconciler 的 <code>workLoop</code>。</li><li><code>react-dom</code>：负责提交阶段（把 reconciler 的副作用应用到浏览器 DOM）以及宿主环境的配置（<code>ReactDOMHostConfig</code>）。</li></ul><p>二、关键模块与职责（深入）</p><ul><li><p><code>react-reconciler</code>（调和细节）</p><ul><li><code>workLoop</code>：驱动调和的循环体，按照是否并发（concurrent）选择不同入口：<code>renderRootConcurrent</code> 或 <code>renderRootSync</code>。</li><li><code>performUnitOfWork(fiber)</code>：每次处理单个 Fiber 节点，职责分成两部分： <ul><li><code>beginWork(fiber)</code>：计算该 fiber 的下一个状态，处理 <code>updateQueue</code>（合并 setState/update），并调用子节点的 reconciliation（例如 <code>reconcileChildren</code>）以生成/复用子 fiber；此阶段可能发生 bailout（当 props/state 未变时跳过子树）。</li><li><code>completeWork(fiber)</code>：完成当前节点，生成 DOM 节点（host component）或收集副作用（例如需要插入/删除/更新的标记），并把这些副作用通过 fiber 链接到父节点（维护 <code>firstEffect</code>/<code>lastEffect</code>/<code>nextEffect</code>）。</li></ul></li><li>effect（副作用）收集：调和阶段不会直接操作 DOM，而是把需要在提交阶段执行的操作记录在 effect list 上，最终由 <code>commitRoot</code> 统一执行。</li></ul></li><li><p><code>react-dom</code>（提交阶段的三部分）</p><ul><li>Before Mutation（变更前）阶段：触发 <code>getSnapshotBeforeUpdate</code> 等需要在 DOM 更新前读取布局信息的生命周期/Hook。</li><li>Mutation（变更）阶段：执行实际的 DOM 操作（插入、删除、更新属性）。</li><li>Layout（布局）阶段：同步调用 <code>useLayoutEffect</code> 的回调与 ref 的更新，这些在变更应用后立即运行。</li></ul></li><li><p><code>scheduler</code>（调度与时间切片）</p><ul><li>核心是提供 <code>unstable_scheduleCallback</code>、<code>unstable_cancelCallback</code>、<code>requestHostCallback</code> 等接口，决定何时调用传入的回调。</li><li>常见宿主实现采用 <code>MessageChannel</code> 驱动微任务轮询；时间切片由 <code>shouldYield()</code> 与 <code>frameDeadline</code> 控制（即长任务中断并在下一帧继续）。</li><li>Scheduler 按“优先级 lane”或“优先级等级”（Immediate、UserBlocking、Normal、Low、Idle）来排序任务，React 的 <code>ensureRootIsScheduled</code> 会把更新映射到合适的优先级并选择 <code>scheduleSyncCallback</code>（同步）或 <code>scheduleCallback</code>（异步）进行注册。</li></ul></li></ul><p>三、典型调用序列（带示例，便于对照源码） 下面以一个并发模式下组件调用 <code>setState</code> 为例，给出从触发到 DOM 更新的关键步骤（数字可与图上箭头对应）：</p><ol><li>组件调用 <code>setState</code>：向当前 fiber 的 <code>updateQueue</code> 推入更新对象。</li><li>React 触发 <code>updateContainer</code> / <code>scheduleUpdateOnFiber</code>：找到根 fiber 并调用 <code>ensureRootIsScheduled(root, currentEventPriority)</code>。</li><li><code>ensureRootIsScheduled</code>：根据更新的 lane/优先级选择调度函数：若为同步优先级调用 <code>scheduleSyncCallback</code>，否则调用 <code>scheduleCallback</code>（并传入合适的优先级）。</li><li>Scheduler 层：通过 <code>requestHostCallback</code> 把任务注册到宿主（例如 <code>MessageChannel</code>），等待宿主唤醒并在合适时间调用回调。</li><li>宿主执行回调到 Scheduler 的 <code>workLoop</code>：Scheduler 检查任务优先级并在当前帧内调用 React 提供的回调（即 reconciler 的 <code>performConcurrentWorkOnRoot</code>）。</li><li><code>performConcurrentWorkOnRoot</code> 调用 reconciler 的 <code>workLoop</code>：开始 <code>performUnitOfWork</code> 的循环，<code>beginWork</code> 创建/更新子 fiber，<code>completeWork</code> 收集 effect。</li><li>当调和完成（或中途被时间切片暂停）并存在副作用时，reconciler 调用 <code>commitRoot</code> 进入提交阶段。</li><li><code>commitRoot</code> 按顺序执行 Before Mutation → Mutation → Layout 阶段，最终 DOM 更新完成，<code>useLayoutEffect</code> 回调执行，refs 被同步更新。</li></ol>',11)]))}const m=o(r,[["render",i]]);export{h as __pageData,m as default};
